```class Solution {
public:
    int distinctSequences(int n) {
        const int MOD = 1e9 + 7;
        vector<int> dp(n + 1, 0);
        dp[0] = 1;
        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= 6; ++j) {
                if (i >= 2) {
                    for (int k = 1; k <= 6; ++k) {
                        if (__gcd(j, k) == 1 && j != k) {
                            dp[i] = (dp[i] + dp[i - 2]) % MOD;
                        }
                    }
                }
                dp[i] = (dp[i] + dp[i - 1]) % MOD;
            }
        }
        return dp[n];
    }
};
